"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { type ReactNode } from "react";

type MarketShellProps = {
  children: ReactNode;
  hideHeader?: boolean;
  shellClassName?: string;
  mainClassName?: string;
};

type NavItem = {
  href: string;
  label: string;
};

const CENTER_NAV: NavItem[] = [
  { href: "/", label: "Home" },
  { href: "/auctions", label: "Auctions" },
];

const RIGHT_NAV: NavItem[] = [
  { href: "/dashboard", label: "Dashboard" },
  { href: "/wallet", label: "Wallet" },
];

function isActive(pathname: string, href: string): boolean {
  if (href === "/") {
    return pathname === "/";
  }

  return pathname === href || pathname.startsWith(`${href}/`);
}

export function MarketShell({
  children,
  hideHeader = false,
  shellClassName,
  mainClassName,
}: MarketShellProps) {
  const pathname = usePathname();
  const shellClasses = ["market-shell", shellClassName].filter(Boolean).join(" ");
  const mainClasses = ["market-main", mainClassName].filter(Boolean).join(" ");

  return (
    <>
      <a className="skip-link" href="#main-content">
        Skip to content
      </a>

      <div className={shellClasses}>
        {!hideHeader ? (
          <header className="market-header">
            <div className="market-header-row">
              <Link href="/" className="brand-link" aria-label="Paddock Auction home">
                <span className="brand-name">Paddock</span>
              </Link>

              <nav className="market-nav market-nav-center" aria-label="Primary navigation">
                {CENTER_NAV.map((item) => (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={isActive(pathname, item.href) ? "is-active" : undefined}
                  >
                    {item.label}
                  </Link>
                ))}
              </nav>

              <div className="header-right">
                <nav className="market-nav market-nav-right" aria-label="Buyer navigation">
                  {RIGHT_NAV.map((item) => (
                    <Link
                      key={item.href}
                      href={item.href}
                      className={isActive(pathname, item.href) ? "is-active" : undefined}
                    >
                      {item.label}
                    </Link>
                  ))}
                </nav>

                <Link href="/login" className="auth-link">
                  Login
                </Link>
                <Link href="/register" className="button button-primary">
                  Register Company
                </Link>
              </div>
            </div>
          </header>
        ) : null}

        <main id="main-content" className={mainClasses}>
          {children}
        </main>
      </div>
    </>
  );
}
